public static void main(Args _args)
{
    DirPartyTable       dirPartyTable;
    TaxInformation_IN   taxInformation_IN;
    DirPartyLocation    dirPartyLocation;
    TaxRegistration     taxRegistration;
    TaxRegistrationType taxRegistrationType;
    VendTable vendTable;
    TaxRegistrationTypeApplicabilityRule taxRegistrationTypeApplicabilityRule;

    str IEC,FSSAI,GST;
      ttsbegin;
        while select forupdate vendTable where vendTable.DataAreaId == "O001"
        {
            select * from dirPartyTable
        where dirPartyTable.RecId == vendTable.Party;

            select * from dirPartyLocation
        where dirPartyLocation.Party == dirPartyTable.RecId
        && dirPartyLocation.IsPrimary == NoYes::Yes;

            while select * from taxRegistration
        where taxRegistration.DirPartyLocation == dirPartyLocation.RecId
            {
                select * from taxRegistrationTypeApplicabilityRule
        where taxRegistrationTypeApplicabilityRule.RecId == taxRegistration.TaxRegistrationTypeApplicabilityRule;
                select * from taxRegistrationType
            where taxRegistrationType.RecId == taxRegistrationTypeApplicabilityRule.TaxRegistrationType;

                if(taxRegistrationType.TaxRegstrationType == "IEC")
                {
                    IEC = taxRegistration.RegistrationNumber;
                }
                if(taxRegistrationType.TaxRegstrationType == "FSSAI")
                {
                    FSSAI = taxRegistration.RegistrationNumber;
                }
                if(taxRegistrationType.TaxRegstrationType == "GST")
                {
                    GST = taxRegistration.RegistrationNumber;
                }
            }
            vendTable.ETGGSTIN = GST;
            vendTable.ETGFSSAIID = FSSAI;
            vendTable.ETGIECCode = IEC;
            vendTable.update();                
        }
        ttscommit;
    }
